Verilating:
```
 module foo(
   input wire clk,
   output reg o
 );
   always @(posedge clk) begin
     if (1'bx) begin
       o <= 1'd1;
     end else begin
       o <= 1'd0;
     end
   end
 endmodule
```

Yields:
```
 VL_INLINE_OPT void Vfoo::_sequent__TOP__1(Vfoo__Syms* __restrict vlSymsp) {
     VL_DEBUG_IF(VL_DBG_MSGF("+    Vfoo::_sequent__TOP__1\n"); );
     Vfoo* const __restrict vlTOPp VL_ATTR_UNUSED = vlSymsp->TOPp;
     // Body
     vlTOPp->o = 1U;
 }

  void Vfoo::_eval(Vfoo__Syms* __restrict vlSymsp) {
     VL_DEBUG_IF(VL_DBG_MSGF("+    Vfoo::_eval\n"); );
     Vfoo* const __restrict vlTOPp VL_ATTR_UNUSED = vlSymsp->TOPp;
     // Body
     if (((IData)(vlTOPp->clk) & (~ (IData)(vlTOPp->__Vclklast__TOP__clk)))) {
         vlTOPp->_sequent__TOP__1(vlSymsp);
     }
     // Final
     vlTOPp->__Vclklast__TOP__clk = vlTOPp->clk;
 }
```

Which is exactly the opposite of the standard, but more interestingly, --x-assign has no effect on this code. Reading V3Unknwon I was hoping the condition would just be replaced with a random value with --x-assign unique, but that does not seem to be the case. Is this intended?
